var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"오래 기다리셨습니다, 주군.","JPN":" お待たせいたしました、我が主。","ENG":" Thank you for your patience, Master.","TWN":"久等了，主君。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"중요한 자리가 있다고 하시기에 몸을 깨끗이 하느라 조금 시간이 걸렸습니다.","JPN":" 重要な席であるとのことでしたので、身を清めるのに少々時間がかかりました。","ENG":" I wanted to make sure I was clean before meeting you for this special occasion.","TWN":"您說是很重要的場合，所以我花了點時間淨身。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"체열이 높아진 탓에 수련을 하지 않아도 금방 땀투성이가 되고 마니까요.","JPN":" 体内温度が上がったせいで訓練せずとも、すぐに汗まみれになってしまいます。","ENG":" Due to obtaining a higher body temperature, I now become sweaty even without training.","TWN":"因為現在體溫很高，就算沒在練劍時也很容易就滿身大汗。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"이런 별난 몸이지만… 그렇게 불편하진 않습니다. 덥지 않은 날씨에도 이렇게 방을 차갑게 해 두신 주군의 배려 덕분이지요.","JPN":" このような変わった体ですが……それほど不快ではありません。それほど暑くない日でも部屋を涼しくしておられる我が主の心遣いのおかげです。","ENG":" As peculiar as my body is... I surprisingly do not feel uncomfortable. It is all thanks to your keeping the room temperature low for me, Master.","TWN":"雖然身體變得有點奇怪…但不會不舒服。這都要感謝您的費心，明明天氣不熱，卻還特地將房間的溫度弄得很涼爽。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"예전에는 이런 작은 친절과 은혜를 무심코 흘려 넘기곤 했습니다.","JPN":" 以前はこんな小さな親切や恩に気づかず通り過ぎてしまっていました。","ENG":" I used to oversee the little things in life. Small favors and acts of kindness, for instance.","TWN":"以前我不太會注意到這種細微的體貼和照顧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"하지만 지금은 어째서인지, 어느때보다 저를 위하는 분들의 심정이 잘 느껴집니다.","JPN":" ですが、最近はなぜか、私によくしてくださる方々の心遣いをより感じるようになりました。","ENG":" But somehow, I now understand the ones who care for me more than I ever have before.","TWN":"但不知道為什麼，我現在很能體會有人替我著想的心情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"다른 점이 있다면 아마… 그 시절에는 강해져야 한다는 집착에 얽매여 마음에 여유가 없었던 탓이겠지요.","JPN":" 前と異なる点があるとすれば……以前は強くならなければという思いにとわれていて余裕がなかったのでしょう。","ENG":" The difference from then and now would be... that I used to be obsessed with becoming stronger. I did not let myself stop and look at my surroundings.","TWN":"為什麼會有這樣的轉變…我想是因為以前的我只執著於要變強，以至於我的心沒有餘裕。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그때의 저는 타인은커녕 자기 감정조차 헤아리지 못하는 차가운 날붙이나 다름없었으니까요.","JPN":" そのときの私は他人どころか、自分自身の感情さえも感じることのできない冷たい刃のような人間でしたから。","ENG":" My heart was cold as iron. I could not even fathom my own feelings, let alone others.","TWN":"那時候的我，別說是別人，我連我自己內心的想法都搞不清楚，彷彿是一把冰冷的刀。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"하지만 이젠 괜찮습니다. 이 힘을 다시 잃게 되더라도, 예전처럼 방황하지 않을 겁니다.","JPN":" 今はもう大丈夫です。たとえこの力が私の中から消えることがあったとしても、以前のように迷うことはありません。","ENG":" But I now know that I will be all right. Even if I lose this power, I will not stray like I did before.","TWN":"不過現在不會了，就算再次失去這股力量，我也不會再像以前那般徬徨。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"제가 마음을 붙여야 할 곳이 어디인지, 제 검이 어디를 향해야 하는지, 이제는 잘 알고 있기 때문입니다.","JPN":" 私がどこに心を寄せ、どこに刀を向ければいいのか、今はよくわかっていますから。","ENG":" Because I now realize where my heart lies... and where the tip of my blade aims.","TWN":"因為我現在很清楚，我的心思該放在哪裡，我的劍又該對準哪裡。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그러니 주군께서도…","JPN":" ですから我が主も……","ENG":" So, Master...","TWN":"所以主君您也…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"주군…? 방금 재채기를 참으신 겁니까?","JPN":" 我が主……？　今のはくしゃみをこらえたのですか？","ENG":" Master...? Were you holding down a sneeze?","TWN":"主君…？您剛才是想打噴嚏嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"역시! 냉방이 너무 강해서 감기에 걸리셨군요!","JPN":" やはり！　冷房が強すぎて風邪を引かれたのですね！","ENG":" I knew it! The cold temperature made you catch cold!","TWN":"我就知道！因為冷氣太強感冒了吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그렇게 배려해주실 필요는 없다고 말씀드렸습니다만.","JPN":" お気遣いいただかなくても大丈夫だとあれほど申し上げましたのに。","ENG":" I insisted that you needn’t care too much for me.","TWN":"就跟您說不用如此費心的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"정말이지… 제 곁에는 왜 이렇게 자신보다 남을 신경 쓰는 분들 밖에 없는 것인지.","JPN":" まったく……どうして私の周りにはこうも自身より他人を気遣う人ばかりなのでしょうか。","ENG":" Goodness... It seems that I am surrounded by those who care for others more than they do for themselves.","TWN":"為什麼…我身邊總是充滿只知道替別人著想的人呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그래도 걱정 마십시오. 이제 저에겐 타인을 위해 희생하는 마음을 지켜드릴 힘이 있으니까요.","JPN":" 今や私には他人のため犠牲になろうとする心をお守りする力がありますので、心配は要りませんが。","ENG":" Do not worry. I am now strong enough to protect your kindness and benevolence.","TWN":" 不過您放心，我現在有能力能夠守護為他人犧牲的心意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"하지만 곁에만 있어주면 충분하다느니 같은 말씀은 곤란합니다!","JPN":" だとしても、傍に居てくれるだけで十分といったお言葉は困ります！","ENG":" However, I will not accept words such as \\"Staying with me is enough\\"!","TWN":"希望您別說只要我在您身邊就好，說這種話我會很困擾！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"제가 금방 따뜻한 차와 약을 가져올 테니, 담요를 제대로 두르고 계십시오.","JPN":" すぐに暖かいお茶とお薬をお持ちしますから、毛布にしっかりくるまっていてください。","ENG":" Please keep yourself warm with this blanket. I will be back with some tea and cough drops.","TWN":"我去替您拿熱茶和藥過來，毯子要蓋好喔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};